bool segmentIntersection(const QPointF& p1, const QPointF& p2, const QPointF& p3, const QPointF& p4, QPointF& point)
{
    qreal d1 = (p2 - p1).crossProduct(p3 - p1);
    qreal d2 = (p2 - p1).crossProduct(p4 - p1);
    qreal d3 = (p4 - p3).crossProduct(p1 - p3);
    qreal d4 = (p4 - p3).crossProduct(p2 - p3);
    if (d1 * d2 < 0 && d3 * d4 < 0) {
        qreal t = d3 / (d3 - d4);
        point = p1 + t * (p2 - p1);
        return true;
    }
    return false;
}
